body.script:
test(function() {
  assert_equals(getComputedStyle(document.getElementById('t1')).backgroundColor, "rgb(0, 255, 0)", "First li should be lime");
  assert_equals(getComputedStyle(document.getElementById('t2')).backgroundColor, "rgb(0, 255, 0)", "Second li should be lime");
  assert_equals(getComputedStyle(document.getElementById('t3')).backgroundColor, "rgb(0, 255, 0)", "Paragraph should be lime");
}, "Groups of selectors");
